PyTypeObject* DoInitWrapperPawn(const UClass* InClass, PyTypeObject* InSuperType, PyObject* InSuperTypes)
{
	if (InClass == nullptr)
	{
		return nullptr;
	}

	if (FUPyWrapperTypeRegistry::Get().HasWrappedClassType(InClass))
	{
		return const_cast<PyTypeObject*>(FUPyWrapperTypeRegistry::Get().GetWrappedClassType(InClass));
	}

	PyTypeObject* PyType = &UPyWrapperPawnType;
	PyType->tp_flags = Py_TPFLAGS_DEFAULT | Py_TPFLAGS_BASETYPE;
	PyType->tp_base = InSuperType != nullptr ? InSuperType : &UPyWrapperObjectType;
	PyType->tp_bases = InSuperTypes;
	PyType->tp_methods = FUPyWrapperPawnPyMethodDefs;
	PyType->tp_getset = FUPyWrapperPawnGetSets;

	if (PyType_Ready(PyType) == 0)
	{
		FUPyWrapperTypeRegistry::Get().RegisterWrappedClassType(InClass, PyType);
		return PyType;
	}

	return nullptr;
}

void InitializeUPyWrapperPawn(UPyGenUtil::FNativePythonModule& ModuleInfo)
{
	FUPyWrapperTypeRegistry::Get().RegisterAutoWrappedClassCreateFunc(APawn::StaticClass(), DoInitWrapperPawn);
}

FUPyWrapperPawn* UPyIsPawn(PyObject* InSelf)
{
	if (InSelf && PyObject_IsInstance(InSelf, (PyObject*)&UPyWrapperPawnType))
	{
		return (FUPyWrapperPawn*)InSelf;
	}
	return nullptr;
}

namespace UPyConversion
{
	FUPyConversionResult Nativize(PyObject* PyObj, APawn*& OutVal, const ESetErrorState SetErrorState)
	{
		if (FUPyWrapperPawn* PyPawn = UPyIsPawn(PyObj))
		{
			if (!FUPyWrapperObjectBase::ValidateInternalState(PyPawn))
			{
				return FUPyConversionResult::Failure();
			}

			OutVal = PyPawn->ValuePtr();
			return FUPyConversionResult::Success();
		}

		UPYCONVERSION_RETURN(FUPyConversionResult::Failure(), TEXT("Nativize"), *FString::Printf(TEXT("Cannot nativize '%s' as 'APawn'"), *UPyUtil::GetFriendlyTypename(PyObj)));
	}
}
